kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command",
    "value": ["mongod", "--config", "/etc/mongod.conf"]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "mongod-config-vol",
      "mountPath": "/etc/mongod.conf",
      "subPath": "mongod.conf"
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "mongo-keyfile-vol",
      "mountPath": "/etc/mongo-keyfile/keyfile",
      "subPath": "keyfile"
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": []
  }
]' 2>&1

kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "mongod-config-vol",
      "configMap": {
        "name": "mongod-config"
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
